const item = $input.first().json;

// ----------------------
// Existing Customer
// ----------------------
const existingCustomer =
    !!item.id ||                     // Airtable record id
    !!item.fields ||                 // Airtable fields
    (Array.isArray(item.records) && item.records.length > 0);

item.existingCustomer = existingCustomer;

// ----------------------
// Lead Score
// ----------------------
let score = 0;

// Email validation
if (item.status === "valid") score += 20;

// Hunter score
const hunterScore = item.hunter_score ?? item.score ?? 0;

if (hunterScore >= 90) {
    score += 15;
} else if (hunterScore >= 70) {
    score += 10;
} else if (hunterScore >= 50) {
    score += 5;
}

// Existing customer
if (existingCustomer) score += 20;

// Company size
const employees = item.data?.metrics?.employees;

switch (employees) {
    case "500+":
    case "201-500":
        score += 15;
        break;

    case "51-200":
        score += 10;
        break;

    case "11-50":
        score += 5;
        break;
}

// Interest
switch (item.Interest) {
    case "AI Automation":
    case "Custom Software Development":
        score += 15;
        break;

    default:
        score += 10;
}

// Company website
if (item["Company Website"]) score += 5;

// Business email
if (item.webmail === false) score += 5;

// Company enrichment successful
if (item.data?.description) score += 5;

// Final score
item.leadScore = score;

// Priority
if (score >= 80) {
    item.priority = "High";
} else if (score >= 50) {
    item.priority = "Medium";
} else {
    item.priority = "Low";
}

// Customer Tag
item.customerTag = existingCustomer
    ? "Existing Customer"
    : "New Customer";

return [{ json: item }];

